var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Krgh!","TWN":"呃！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 교수님. 대체 왜 마음에도 없는 소리를 하시는 겁니까?","JPN":"バーミンガム教授、なぜ心にもないことを言うんですか？","ENG":"Professor Birmingham. Why are you saying things you don't even believe?","TWN":"伯明罕教授，為什麼說違心的話呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런 거짓말을, 대체 왜……!!","JPN":"いったいなぜ、そんな嘘を……！！","ENG":"Why would you lie like that...?!","TWN":"為什麼要說那種謊……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"거짓말이 아닐세. 자네들이 하는 건 그저 현실에서 등 돌린 기사놀이에 불과해.","JPN":"嘘ではない。君たちのやっていることは、現実から目を背けた騎士ごっこに過ぎない。","ENG":"It's no lie. What you're doing is nothing more than playing knights while turning your back on reality.","TWN":"這不是謊言。你們所做的不過是背離現實的騎士遊戲罷了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니면, 아직도 모두를 구하리라는 헛된 희망을 품고 있는 건가?","JPN":"それとも、まだ皆を救えるという虚しい希望を抱いているのか？","ENG":"Or are you still clinging to that hollow hope that you can save everyone?","TWN":"還是說，你仍然懷抱著拯救所有人的虛妄希望？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"정신 차리게. 여긴 현실이야. 모두가 행복해지는 결말은 존재하지 않아.","JPN":"目を覚ませ。ここは現実だ。皆が幸せになる結末など存在しない。","ENG":"Wake up. This is reality. There is no such thing as a happy ending for all.","TWN":"清醒點，這裡是現實。不存在讓所有人都幸福的結局。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"목숨을 걸고 지키겠다는 필사의 각오도… 압도적인 힘 앞에서는 종잇장처럼 흩어질 뿐이다.","JPN":"命をかけて守るという必死の覚悟も……圧倒的な力の前では成す術もなく散ってゆくだけだ。","ENG":"Even a life-risking resolve to protect others... crumbles like paper before overwhelming power.","TWN":"即使是誓死守護的決心……在壓倒性的力量面前也不過是紙片般的脆弱。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면, 어릴 적 저희 남매에게 살아남을 수 있는 희망을 주신 이유는 뭡니까?","JPN":"だったらなぜ、幼い私たち兄妹に生き残れるという希望を与えたのですか？","ENG":"Then, why did you give my brother and me hope when we were children?","TWN":"那麼，你給我們兄妹帶來生存希望的理由是什麼呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 인도자를 실패했다 말하면서… 어째서 그런 슬픈 표정을 짓고 계신 거죠?","JPN":"星の導き手は失敗したと言いながら……なぜそんな悲しい顔をしているんですか？","ENG":"You call the Star Guide a failure... Yet why do you look so heartbroken?","TWN":"說自己沒能成為星之引導者……為什麼露出如此悲傷的表情呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……별 의미 없던 행동이 자네에게 희망의 별빛이 되어주었나 보군.","JPN":"……大した意味もない行動が、君には希望の光となってしまったようだ。","ENG":"...Seems a meaningless act of kindness ended up being your guiding starlight.","TWN":"……看來我無意間的舉動成了你的希望之光啊。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그렇다면, 그것을 거두는 것 또한 내 몫이겠지.","JPN":"ならば、それを消すのも私の役目だろう。","ENG":"Then it's only right that I'm the one to extinguish it.","TWN":"那麼，將它熄滅也是我的責任吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"알렌 경. 저는 당신과 싸우고 싶지 않습니다!","JPN":"アレン卿、私はあなたと戦いたくありません！","ENG":"Sir Allen, I don't want to fight you!","TWN":"艾倫卿，我不想和你戰鬥！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"대련 도중 자네의 검은 나를 날카롭게 겨눴는데, 정작 전장에서는 본래의 쓰임조차 잃었군.","JPN":"かつての手合わせで、君の剣は鋭く私を狙えていた。だが、肝心な戦場では本来の力を発揮できていないな。","ENG":"Your sword was sharp when we sparred, but now on the battlefield, it's forgotten its purpose.","TWN":"對練時你的劍鋒直指我，而在戰場上卻失去了原本的用途。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아무런 각오도 없이 전장에 서는 게, 자네가 말하는 <color=#ffd34c>기사도</color>인가?","JPN":"何の覚悟もなく戦場に立つのが、君の言う<color=#ffd34c>騎士道</color>なのか？","ENG":"To stand on the field without resolve. Is that what you call <color=#ffd34c>chivalry</color>?","TWN":"毫無覺悟地站在戰場上，就是你所說的<color=#ffd34c>騎士精神</color>嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크윽…!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"呃…！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드, 전개!!","JPN":"ヴァルゴソード、展開！！","ENG":"Virgo Sword Draw!","TWN":"布林加夫之劍，展開！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"喔？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드가… 반응하지 않아?","JPN":"ヴァルゴソードが……反応しない？","ENG":"Virgo Sword... isn't responding?","TWN":"布林加夫之劍……沒有反應嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"싸울 의지도, 무언가를 포기할 각오조차 없는 이에게 별의 무구가 응답할 리 없지.","JPN":"戦う意志も、何かを捨てる覚悟もない者に、星の武具が応えるはずがない。","ENG":"No Star Armament would answer someone with no will to fight, no readiness to sacrifice something.","TWN":"既沒有戰鬥的意志，也沒有放棄某些東西的覺悟，星之武具是不會回應這種人的。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그만 끝내게. 이게 내가 자네에게 해줄 수 있는 마지막 배려야.","JPN":"もう終わりにしたまえ。これが私が君にしてやれる最後の気遣いだ。","ENG":"End this. This is the last kindness I can offer you.","TWN":"就此結束吧。這是我能給你的最後的關照了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그럴 순 없습니다! 무구가 부름에 응하지 않더라도, 저는 당신을 구해야만……!!","JPN":"そういうわけにはいきません！　武具が応えなくても、私はあなたを救わなければ……！！","ENG":"No! Even if the Armament doesn't respond, I still have to save you...!","TWN":"那是不可能的！即使武器沒有回應，我也必須救你……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이건…… 눈?","JPN":"これは……雪？","ENG":"Is this... snow?","TWN":"這是……雪？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……눈이라고? 성역에?","JPN":"……雪だと？　聖域に？","ENG":"...Snow? In the Sanctuary?","TWN":"……雪？在聖域裡？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};